"""Typed exception hierarchy for the SDK.

Only the errors actually raised on the synchronous (caller-facing) path live here.
Background delivery failures are not raised — they are surfaced via the transport's
``on_drop`` callback with the raw HTTP status — so there are no separate
rate-limit/validation exception types.
"""

from __future__ import annotations


class AnalyticsError(Exception):
    """Base class for every error raised by the SDK."""


class AuthError(AnalyticsError):
    """401 — the bearer token is missing, malformed, or expired."""


class TransportError(AnalyticsError):
    """5xx / timeout / network failure — retryable."""
